-- ═══════════════════════════════════════════════════════════════════════════════
-- 🏆 ULTIMATE VERIFICATION — ALL 7 V9 FILES
-- ═══════════════════════════════════════════════════════════════════════════════
SELECT '🏆 GRAND TOTAL' AS label, COUNT(*) AS entries FROM industry_solutions;
SELECT product_type, COUNT(*) AS total FROM industry_solutions GROUP BY product_type;
SELECT '📦 UNIQUE PRODUCTS' AS label, COUNT(DISTINCT product_slug) AS total FROM industry_solutions;
SELECT '🏭 INDUSTRIES' AS label, COUNT(DISTINCT industry_slug) AS total FROM industry_solutions;
SELECT '📊 AVG/INDUSTRY' AS label, ROUND(COUNT(*)::numeric / COUNT(DISTINCT industry_slug), 1) AS avg FROM industry_solutions;
SELECT industry_slug, COUNT(*) AS solutions FROM industry_solutions GROUP BY industry_slug ORDER BY solutions ASC LIMIT 10;
SELECT industry_slug, COUNT(*) AS solutions FROM industry_solutions GROUP BY industry_slug ORDER BY solutions DESC LIMIT 10;
SELECT category, COUNT(DISTINCT product_slug) AS unique_products FROM industry_solutions GROUP BY category ORDER BY unique_products DESC LIMIT 50;